// Parse incoming payload from Supabase generate-social-content function
// Split content items into:
//   - video_items: tiktok, instagram, youtube, facebook (need voiceover + video)
//   - text_items: pinterest, linkedin (text/image posts only)

const payload = $input.first().json.body || $input.first().json;

const videoItems = (payload.content_items || []).filter(item =>
  ['tiktok', 'instagram', 'youtube', 'facebook'].includes(item.platform)
);

const textItems = (payload.content_items || []).filter(item =>
  ['pinterest', 'linkedin'].includes(item.platform)
);

// Use first video item's script for voiceover (all video platforms share same script)
const primaryVideoItem = videoItems[0] || {};

return [{
  json: {
    run_date: payload.run_date,
    content_angle: payload.content_angle,
    pexels_query: payload.pexels_query || 'fitness workout health',
    voice_gender: payload.voice_gender || 'female',
    script: payload.script || primaryVideoItem.script || '',
    video_items: videoItems,
    text_items: textItems,
    all_items: payload.content_items || [],
    dry_run: payload.dry_run || false,
  }
}];

// Build the audio public URL from Supabase Storage
const supabaseUrl = 'https://mxggxpoxgqubojvumjlt.supabase.co';
const bucketName = 'yfit-voiceovers';

const parseData = $('Parse Supabase Payload').first().json;
const runDate = parseData.run_date || new Date().toISOString().split('T')[0];
const rawAngle = parseData.content_angle || 'workout';
const sanitizedAngle = rawAngle.replace(/[^a-z0-9\-]/gi, '_').substring(0, 80);
const audioUrl = `${supabaseUrl}/storage/v1/object/public/${bucketName}/voiceovers/${runDate}_${sanitizedAngle}.mp3`;

const firstVideoItem = (parseData.video_items || [])[0] || {};
const captionText = ((firstVideoItem.caption || parseData.script || '').split('\n')[0]).substring(0, 60);

return [{
  json: {
    ...parseData,
    voiceover_url: audioUrl,
    caption_text: captionText,
    video_items: parseData.video_items,
    text_items: parseData.text_items,
  }
}];

// ─────────────────────────────────────────────────────────────────────────────
// UPDATED v3: Append platform-specific UTM links to every caption
// This is the ONLY node that changed from v2.
// ─────────────────────────────────────────────────────────────────────────────

const result = $input.first().json;

if (!result.success || !result.video_url) {
  throw new Error('Video assembly failed: ' + (result.error || 'No video URL returned'));
}

const parseData = $('Parse Supabase Payload').first().json;

// UTM base — /go page is the social landing page, optimised for cold traffic
const GO_BASE = 'https://yfitai.com/go';
const SIGNUP_BASE = 'https://app.yfitai.com/signup';

// Determine campaign tag from content angle (max 40 chars, URL-safe)
const campaign = (parseData.content_angle || 'fitness')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '_')
  .substring(0, 40)
  .replace(/^_+|_+$/g, '');

// Platform-specific CTA appended AFTER the GPT-generated caption
const platformCTA = {
  tiktok:    `\n\n🔗 Link in bio to try free`,
  instagram: `\n\n🔗 Link in bio to try free`,
  youtube:   `\n\n🔗 Try YFIT free → ${SIGNUP_BASE}?utm_source=youtube&utm_medium=shorts&utm_campaign=${campaign}`,
  facebook:  `\n\n${GO_BASE}?utm_source=facebook&utm_medium=post&utm_campaign=${campaign}`,
};

// Return one item per video platform with UTM-enriched caption
return parseData.video_items.map(item => ({
  json: {
    platform: item.platform,
    video_url: result.video_url,
    caption: (item.caption || '') + (platformCTA[item.platform] || ''),
    title: item.title || item.script ? (item.script || '').substring(0, 100) : 'YFIT Fitness Tip',
    hashtags: item.hashtags || [],
    content_angle: parseData.content_angle,
    run_date: parseData.run_date,
  }
}));

// ─────────────────────────────────────────────────────────────────────────────
// UPDATED v3: Append UTM links to LinkedIn and Pinterest text posts
// ─────────────────────────────────────────────────────────────────────────────

const parseData = $('Parse Supabase Payload').first().json;

const GO_BASE = 'https://yfitai.com/go';
const SIGNUP_BASE = 'https://app.yfitai.com/signup';

const campaign = (parseData.content_angle || 'fitness')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '_')
  .substring(0, 40)
  .replace(/^_+|_+$/g, '');

return (parseData.text_items || []).map(item => {
  let captionWithLink = item.caption || item.script || '';
  const hashtags = (item.hashtags || []).join(' ');

  if (item.platform === 'linkedin') {
    // LinkedIn: keep caption clean, add link as a separate line at the end
    // (the first comment approach is manual — for automated posting, include in caption)
    captionWithLink += `\n\nTry YFIT free (no credit card): ${SIGNUP_BASE}?utm_source=linkedin&utm_medium=post&utm_campaign=${campaign}`;
  } else if (item.platform === 'pinterest') {
    // Pinterest: link goes in the destination URL field, not the caption
    // Caption stays clean for the pin description
    captionWithLink = captionWithLink; // no change to caption
  }

  return {
    json: {
      platform: item.platform,
      caption: captionWithLink,
      hashtags: hashtags,
      // Pinterest destination URL — this is where the pin clicks through to
      destination_url: item.platform === 'pinterest'
        ? `${GO_BASE}?utm_source=pinterest&utm_medium=pin&utm_campaign=${campaign}`
        : undefined,
    }
  };
});

// Collect results from both video and text posting branches
const videoResult = $input.first().json;
console.log('Post result:', JSON.stringify(videoResult));

return [{
  json: {
    success: true,
    posted_at: new Date().toISOString(),
    result: videoResult,
  }
}];

// ─────────────────────────────────────────────────────────────────────────────
// UPDATED v3: Test Data now uses the MEDICATION ANGLE script
// This is the problem-first hook that drives social traffic to /go
// Set dry_run: false to actually post. Set dry_run: true to preview only.
// ─────────────────────────────────────────────────────────────────────────────

return [{
  json: {
    run_date: new Date().toISOString().split('T')[0],
    content_angle: 'your_fitness_app_doesnt_know_your_medications',
    pexels_query: 'person checking phone medication pills fitness',
    voice_gender: 'female',
    dry_run: true,  // ← SET TO false TO ACTUALLY POST
    script: 'Your fitness app has no idea what medications you are on — and that is actually dangerous. If you take Metformin, beta blockers, SSRIs, or statins — intense cardio can cause blood sugar crashes, heart rate miscalculations, and recovery failures. And your app? It gives you the same plan as someone on zero medications. YFIT is the only fitness app that actually knows your prescriptions. It flags dangerous workout combinations, adjusts your macros, and generates a report your doctor can use. It is completely free to start. Link in my bio — no credit card, no gym needed.',
    content_items: [
      {
        platform: 'tiktok',
        script: 'Your fitness app has no idea what medications you are on — and that is actually dangerous.',
        caption: 'Your fitness app is lying to you 💊 #fitness #medication #health #yfitai #fitnesstips',
        hashtags: ['#fitness', '#medication', '#health', '#yfitai', '#fitnesstips']
      },
      {
        platform: 'instagram',
        script: 'Your fitness app has no idea what medications you are on.',
        caption: '66% of adults take prescription medication.\n\nZero fitness apps account for it.\n\nYFIT does. 💊',
        hashtags: ['#fitness', '#medication', '#health', '#yfitai', '#wellnessapp']
      },
      {
        platform: 'youtube',
        title: 'Your fitness app doesn\'t know about your medications (and it\'s dangerous)',
        script: 'Your fitness app has no idea what medications you are on — and that is actually dangerous.',
        caption: 'There is something every fitness app is missing — and if you are on medication, it could be hurting your progress.',
        hashtags: ['#fitness', '#medication', '#yfitai', '#YouTubeShorts']
      },
      {
        platform: 'facebook',
        script: 'Your fitness app has no idea what medications you are on.',
        caption: 'If you are on any prescription medication and trying to get fit — this is for you.\n\nMost fitness apps treat everyone the same. YFIT AI is the only fitness app that actually accounts for your medications.',
        hashtags: ['#fitness', '#medication', '#health', '#yfitai']
      },
      {
        platform: 'linkedin',
        title: 'The fitness-medication gap no app is solving (until now)',
        script: '66 percent of adults take at least one prescription medication. Zero mainstream fitness apps account for this.',
        caption: 'A statistic that surprises most people: 66% of adults take at least one prescription medication.\n\nA statistic that surprises no one in healthcare: zero mainstream fitness apps account for this.\n\nYFIT AI is the first fitness application built to address this gap.',
        hashtags: ['#Fitness', '#Wellness', '#YFIT', '#HealthTech']
      },
      {
        platform: 'pinterest',
        title: 'The only fitness app that knows your medications',
        script: '',
        caption: 'YFIT AI tracks your prescriptions alongside your workouts and nutrition — and flags dangerous interactions before they happen. Free to start.',
        hashtags: ['#fitness', '#medication', '#yfitai', '#healthylifestyle']
      }
    ]
  }
}];

// Dry Run Logger — summarizes what would have been posted
const items = $input.all();

const report = {
  dry_run: true,
  timestamp: new Date().toISOString(),
  total_platforms: items.length,
  summary: items.map(item => ({
    platform: item.json.platform,
    caption_preview: (item.json.caption || item.json.body || '').substring(0, 150) + '...',
    hashtags: item.json.hashtags || [],
    status: 'WOULD_POST'
  }))
};

console.log('\n=== DRY RUN COMPLETE ===');
console.log(JSON.stringify(report, null, 2));
console.log('\nTo post for real: set dry_run: false in the Test Data node');

return [{ json: report }];

// Dry Run Logger (Text Posts)
const items = $input.all();

const report = {
  dry_run: true,
  post_type: 'text',
  timestamp: new Date().toISOString(),
  total_platforms: items.length,
  summary: items.map(item => ({
    platform: item.json.platform,
    caption_preview: (item.json.caption || '').substring(0, 150) + '...',
    destination_url: item.json.destination_url || '(none)',
    status: 'WOULD_POST'
  }))
};

console.log('\n=== DRY RUN — TEXT POSTS ===');
console.log(JSON.stringify(report, null, 2));

return [{ json: report }];

// Rename binary field to 'data' for the Upload node
const item = $input.first();
const binaryData = item.binary || {};
const binaryKeys = Object.keys(binaryData);
console.log('Binary fields from ElevenLabs:', binaryKeys);

if (binaryKeys.length === 0) {
  throw new Error('No binary audio data received from ElevenLabs');
}

const firstKey = binaryKeys[0];
const audioData = binaryData[firstKey];
console.log('Audio field:', firstKey, '- mimeType:', audioData.mimeType);

return [{
  json: item.json,
  binary: {
    data: {
      ...audioData,
      mimeType: 'audio/mpeg',
      fileExtension: 'mp3'
    }
  }
}];
